import { PermissionCache } from '../../../../src/infrastructure/cache/PermissionCache';
import { UserId } from '../../../../src/domain/value-objects/UserId';

jest.mock('redis', () => {
  const clients: Array<Record<string, jest.Mock>> = [];

  const createClient = jest.fn(() => {
    const client = {
      connect: jest.fn().mockResolvedValue(undefined),
      quit: jest.fn().mockResolvedValue(undefined),
      subscribe: jest.fn().mockResolvedValue(undefined),
      publish: jest.fn().mockResolvedValue(undefined),
      get: jest.fn().mockResolvedValue(null),
      setEx: jest.fn().mockResolvedValue(undefined),
      del: jest.fn().mockResolvedValue(0),
      keys: jest.fn().mockResolvedValue([])
    };

    clients.push(client);
    return client;
  });

  return {
    createClient,
    __getClients: () => clients,
    __resetClients: () => {
      clients.length = 0;
    }
  };
});

const { __getClients, __resetClients } = jest.requireMock('redis') as {
  __getClients: () => Array<Record<string, jest.Mock>>;
  __resetClients: () => void;
};

describe('PermissionCache', () => {
  beforeEach(() => {
    __resetClients();
    jest.clearAllMocks();
  });

  it('does not subscribe before connect is called', () => {
    // Act
    new PermissionCache('redis://test');

    // Assert
    const mockClients = __getClients();
    expect(mockClients).toHaveLength(2);
    const pubSubClient = mockClients[1];
    expect(pubSubClient.subscribe).not.toHaveBeenCalled();
  });

  it('subscribes to channels after connect and only once', async () => {
    const cache = new PermissionCache('redis://test');

    await cache.connect();
    await cache.connect(); // Second call should be a no-op

    const mockClients = __getClients();
    expect(mockClients).toHaveLength(2);
    const [cacheClient, pubSubClient] = mockClients;

    expect(cacheClient.connect).toHaveBeenCalledTimes(1);
    expect(pubSubClient.connect).toHaveBeenCalledTimes(1);
    expect(pubSubClient.subscribe).toHaveBeenCalledTimes(2);
    expect(pubSubClient.subscribe).toHaveBeenNthCalledWith(
      1,
      'permission:invalidate',
      expect.any(Function)
    );
    expect(pubSubClient.subscribe).toHaveBeenNthCalledWith(
      2,
      'permission:invalidate:role',
      expect.any(Function)
    );
  });

  it('handles invalidate calls even when not connected yet', async () => {
    const cache = new PermissionCache('redis://test');
    const userId = UserId.generate();

    await expect(cache.invalidate(userId)).resolves.toBeUndefined();
  });
});
